import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import Ajv2020 from "ajv/dist/2020.js";
import standaloneCode from "ajv/dist/standalone/index.js";
import { SCHEMA_PATHS, CANONICAL_SCHEMA_PATHS } from "../src/lib/schemas.js";

const repoRoot = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const outputPath = resolve(repoRoot, "functions/_generated/diligenceValidatorBundle.js");

function toFilePath(schemaPath) {
  return resolve(repoRoot, schemaPath.replace(/^\//, ""));
}

function validatorExportName(schemaId) {
  return `validate_${schemaId.replace(/[^a-zA-Z0-9_$]/g, "_")}`;
}

async function readSchema(schemaPath) {
  const raw = await readFile(toFilePath(schemaPath), "utf8");
  return JSON.parse(raw);
}

async function main() {
  const ajv = new Ajv2020({
    allErrors: true,
    strict: false,
    validateFormats: false,
    allowUnionTypes: true,
    code: {
      source: true,
      esm: true,
      lines: true
    }
  });

  const standaloneExports = {};
  const schemaKeyToExport = {};

  for (const [schemaId, schemaPath] of Object.entries(SCHEMA_PATHS)) {
    const schema = await readSchema(schemaPath);
    const exportName = validatorExportName(schemaId);

    ajv.addSchema(schema, schemaId);
    standaloneExports[exportName] = schemaId;
    schemaKeyToExport[schemaId] = exportName;
  }

  const validatorSource = standaloneCode(ajv, standaloneExports);
  const canonicalKeyToSchemaId = {};

  for (const [canonicalKey, schemaPath] of Object.entries(CANONICAL_SCHEMA_PATHS)) {
    const schemaId = Object.entries(SCHEMA_PATHS).find(([, path]) => path === schemaPath)?.[0];
    if (schemaId) canonicalKeyToSchemaId[canonicalKey] = schemaId;
  }

  const validatorMapSource = Object.entries(schemaKeyToExport)
    .map(([schemaId, exportName]) => `  ${JSON.stringify(schemaId)}: ${exportName}`)
    .join(",\n");

  const metadata = JSON.stringify({
    generated_at: new Date().toISOString(),
    schema_key_to_export: schemaKeyToExport,
    canonical_key_to_schema_id: canonicalKeyToSchemaId
  }, null, 2);

  const source = `${validatorSource}

// Runtime lookup metadata generated by scripts/generate-diligence-validator-bundle.mjs.
export const DILIGENCE_VALIDATOR_META = Object.freeze(${metadata});

const VALIDATORS = Object.freeze({
${validatorMapSource}
});

export function resolveValidatorKey(schemaKey) {
  const directKey = String(schemaKey || "").trim();
  if (VALIDATORS[directKey]) return directKey;
  return DILIGENCE_VALIDATOR_META.canonical_key_to_schema_id[directKey] || directKey;
}

export function validateGeneratedSchema(schemaKey, data) {
  const resolvedKey = resolveValidatorKey(schemaKey);
  const validate = VALIDATORS[resolvedKey];

  if (typeof validate !== "function") {
    return {
      ok: false,
      schemaKey,
      resolvedKey,
      errors: [{
        keyword: "schema_lookup",
        instancePath: "",
        schemaPath: "",
        message: "Generated validator not found for " + schemaKey,
        params: {}
      }]
    };
  }

  const ok = validate(data);
  return {
    ok,
    schemaKey,
    resolvedKey,
    errors: validate.errors || []
  };
}
`;

  await mkdir(dirname(outputPath), { recursive: true });
  await writeFile(outputPath, source, "utf8");

  console.log(`Generated ${outputPath}`);
  console.log(`Validator count: ${Object.keys(schemaKeyToExport).length}`);
}

main().catch((error) => {
  console.error("Failed to generate Diligence validator bundle.");
  console.error(error?.stack ?? error?.message ?? error);
  process.exitCode = 1;
});
